parameters:
{
  "sources": {
    "albums": {
      "db": "stg",
      "table": "JsonPlaceholder_Albums",
      "business_keys": [
        "album_id"
      ],
      "filter": {
        "where_clause": "CAST(stg_load_date AS DATE) > '{{LastRunDateTime}}' AND album_id IS NOT NULL"
      }
    },
    "photos": {
      "db": "stg",
      "table": "JsonPlaceholder_Photos",
      "business_keys": [
        "photo_id"
      ],
      "filter": {
        "where_clause": "CAST(stg_load_date AS DATE) > '{{LastRunDateTime}}' AND photo_id IS NOT NULL AND album_id IS NOT NULL"
      }
    }
  },
  "target": {
    "db": "int",
    "table": "Photo_Album_Stats",
    "business_keys": [
      "Album_ID"
    ],
    "write_mode": "truncate_insert"
  },
  "transformation": {
    "steps": [
      {
        "step_id": 10,
        "name": "read_albums",
        "type": "read_source",
        "config": {
          "source_name": "albums",
          "alias": "df_albums"
        }
      },
      {
        "step_id": 20,
        "name": "dedup_albums",
        "type": "deduplicate",
        "config": {
          "input_df": "df_albums",
          "alias": "df_albums_dedup",
          "use_source_business_keys": true,
          "source_name": "albums",
          "order_by": [
            {
              "column": "stg_load_date",
              "direction": "desc"
            }
          ]
        }
      },
      {
        "step_id": 30,
        "name": "read_photos",
        "type": "read_source",
        "config": {
          "source_name": "photos",
          "alias": "df_photos"
        }
      },
      {
        "step_id": 40,
        "name": "dedup_photos",
        "type": "deduplicate",
        "config": {
          "input_df": "df_photos",
          "alias": "df_photos_dedup",
          "use_source_business_keys": true,
          "source_name": "photos",
          "order_by": [
            {
              "column": "stg_load_date",
              "direction": "desc"
            }
          ]
        }
      },
      {
        "step_id": 50,
        "name": "count_photos_by_album",
        "type": "aggregate",
        "config": {
          "input_df": "df_photos_dedup",
          "alias": "df_photo_counts",
          "group_by": [
            "album_id"
          ],
          "aggregations": [
            {
              "function": "count",
              "alias": "photo_count"
            }
          ]
        }
      },
      {
        "step_id": 60,
        "name": "rename_photo_counts",
        "type": "select",
        "config": {
          "input_df": "df_photo_counts",
          "alias": "df_photo_counts_sel",
          "columns": [
            {
              "expr": "album_id",
              "alias": "photo_album_id"
            },
            {
              "expr": "photo_count",
              "alias": "photo_count"
            }
          ]
        }
      },
      {
        "step_id": 70,
        "name": "join_albums_to_counts",
        "type": "join",
        "config": {
          "left_df": "df_albums_dedup",
          "right_df": "df_photo_counts_sel",
          "alias": "df_joined",
          "join_type": "left",
          "on": [
            {
              "left": "album_id",
              "right": "photo_album_id"
            }
          ]
        }
      },
      {
        "step_id": 80,
        "name": "select_album_stats",
        "type": "select",
        "config": {
          "input_df": "df_joined",
          "alias": "df_selected",
          "columns": [
            {
              "expr": "album_id",
              "alias": "Album_ID"
            },
            {
              "expr": "user_id",
              "alias": "Owner_User_ID"
            },
            {
              "expr": "album_title",
              "alias": "Album_Title"
            },
            {
              "expr": "coalesce(photo_count, 0)",
              "alias": "Photo_Count"
            },
            {
              "expr": "stg_load_date",
              "alias": "stg_load_date"
            },
            {
              "expr": "batch_id",
              "alias": "batch_id"
            }
          ]
        }
      },
      {
        "step_id": 90,
        "name": "add_system_fields",
        "type": "add_system_fields",
        "config": {
          "input_df": "df_selected",
          "alias": "df_with_sys"
        }
      },
      {
        "step_id": 100,
        "name": "compute_hash",
        "type": "compute_hash",
        "config": {
          "input_df": "df_with_sys",
          "alias": "df_hashed"
        }
      },
      {
        "step_id": 110,
        "name": "write_target",
        "type": "write_target",
        "config": {
          "input_df": "df_hashed"
        }
      }
    ]
  }
}
